from enum import Enum
import anthropic

class AgentErrorCode(str, Enum):
    RATE_LIMIT       = "rate_limit"
    CONTEXT_OVERFLOW = "context_overflow"
    OVERLOADED       = "overloaded"
    TOOL_FAILURE     = "tool_failure"
    SAFETY_REFUSAL   = "safety_refusal"
    NETWORK          = "network_error"
    UNKNOWN          = "unknown"

def classify_error(exc: Exception) -> tuple[AgentErrorCode, str]:
    """Map an exception to a (code, user-facing message) pair."""
    if isinstance(exc, anthropic.RateLimitError):
        return AgentErrorCode.RATE_LIMIT, (
            "Too many requests. We'll automatically retry in a moment."
        )
    if isinstance(exc, anthropic.BadRequestError):
        if "prompt is too long" in str(exc) or "maximum context" in str(exc).lower():
            return AgentErrorCode.CONTEXT_OVERFLOW, (
                "This conversation is too long to continue. "
                "Start a new session or ask me to summarise our conversation first."
            )
        return AgentErrorCode.UNKNOWN, "The request was invalid. Please try again."
    if isinstance(exc, anthropic.APIStatusError) and exc.status_code == 529:
        return AgentErrorCode.OVERLOADED, (
            "Claude is busy right now. Retrying automatically..."
        )
    if isinstance(exc, anthropic.APIConnectionError):
        return AgentErrorCode.NETWORK, (
            "Connection lost. Check your internet connection and try again."
        )
    return AgentErrorCode.UNKNOWN, "Something went wrong. Please try again."

import json, asyncio
from fastapi.responses import StreamingResponse
from anthropic import AsyncAnthropic, RateLimitError, APIStatusError, BadRequestError

client = AsyncAnthropic()

async def streaming_agent(history: list, tools: list):
    """Wrap the Claude stream in a resilient error-emitting generator."""
    max_retries = 3
    retry_delay = 5.0   # seconds

    for attempt in range(max_retries):
        try:
            async with client.messages.stream(
                model="claude-opus-4-8",
                max_tokens=4096,
                messages=history,
                tools=tools,
            ) as stream:
                async for event in stream:
                    yield event
                return   # success — stop retry loop

        except RateLimitError:
            if attempt < max_retries - 1:
                yield {"_error": "rate_limit", "retry_in": retry_delay, "attempt": attempt + 1}
                await asyncio.sleep(retry_delay)
                retry_delay *= 2
            else:
                yield {"_error": "rate_limit_exhausted",
                       "message": "Rate limit reached. Please wait a minute and try again."}
                return

        except APIStatusError as e:
            if e.status_code == 529 and attempt < max_retries - 1:
                yield {"_error": "overloaded", "retry_in": retry_delay}
                await asyncio.sleep(retry_delay)
                retry_delay *= 2
            else:
                yield {"_error": "api_error", "status": e.status_code,
                       "message": "Claude is temporarily unavailable. Please try again."}
                return

        except BadRequestError as e:
            if "too long" in str(e).lower():
                yield {"_error": "context_overflow",
                       "message": "Conversation is too long. Start a new session."}
            else:
                yield {"_error": "bad_request", "message": str(e)}
            return

        except Exception as e:
            yield {"_error": "unknown", "message": "An unexpected error occurred."}
            return

async def sse_event_stream(history, tools):
    async for event in streaming_agent(history, tools):
        if isinstance(event, dict) and "_error" in event:
            # Emit a typed error SSE event
            yield f"data: {json.dumps({'type': 'error', **{k: v for k,v in event.items() if k != '_error'}, 'code': event['_error']})}\n\n"
        else:
            # Normal streaming events
            if hasattr(event, "type"):
                if event.type == "content_block_delta" and hasattr(event.delta, "text"):
                    yield f"data: {json.dumps({'type': 'text', 'text': event.delta.text})}\n\n"

// ErrorCard.tsx - unified error display component
interface ErrorEvent {
  code: string;
  message: string;
  retry_in?: number;
  attempt?: number;
}

export function ErrorCard({
  error,
  onRetry,
  onNewSession,
}: {
  error: ErrorEvent;
  onRetry?: () => void;
  onNewSession?: () => void;
}) {
  const isTransient = ["rate_limit", "overloaded", "network_error"].includes(error.code);
  const needsNewSession = error.code === "context_overflow";

  return (
    <div className="flex items-start gap-3 rounded-xl border p-4 text-sm my-2
                    bg-red-950/60 border-red-800">
      <span className="text-red-400 text-lg mt-0.5">
        {isTransient ? "⏳" : "⚠"}
      </span>
      <div className="flex-1 min-w-0">
        <p className="text-red-200 font-medium">{error.message}</p>
        {error.retry_in && (
          <RetryCountdown seconds={error.retry_in} onDone={onRetry} />
        )}
        <p className="text-red-600 text-xs mt-1 font-mono">{error.code}</p>
      </div>
      <div className="flex gap-2 shrink-0">
        {isTransient && onRetry && !error.retry_in && (
          <button onClick={onRetry}
                  className="text-xs text-red-300 hover:text-red-100 underline">
            Retry now
          </button>
        )}
        {needsNewSession && onNewSession && (
          <button onClick={onNewSession}
                  className="text-xs bg-indigo-700 hover:bg-indigo-600 text-white
                             px-2 py-1 rounded">
            New session
          </button>
        )}
      </div>
    </div>
  );
}

function RetryCountdown({ seconds, onDone }: { seconds: number; onDone?: () => void }) {
  const [remaining, setRemaining] = useState(Math.ceil(seconds));
  useEffect(() => {
    if (remaining <= 0) { onDone?.(); return; }
    const t = setTimeout(() => setRemaining(r => r - 1), 1000);
    return () => clearTimeout(t);
  }, [remaining]);
  return <p className="text-red-400 text-xs mt-1">Retrying in {remaining}s...</p>;
}

# Tool failure handling: catch, log, and continue
import logging
from typing import Any

logger = logging.getLogger(__name__)

async def safe_run_tool(name: str, tool_input: dict) -> dict:
    """Run a tool and return a structured result including error info."""
    try:
        result = await TOOL_REGISTRY[name](tool_input)
        return {"success": True, "result": result}
    except Exception as e:
        logger.error("Tool %s failed: %s", name, e, exc_info=True)
        return {
            "success": False,
            "error": type(e).__name__,
            "message": str(e)[:200],
        }

# In the agentic loop, when a tool result is an error:
def format_tool_result_for_claude(tool_use_id: str, run_result: dict) -> dict:
    if run_result["success"]:
        content = json.dumps(run_result["result"])
    else:
        # Tell Claude what went wrong so it can self-recover
        content = (
            f"Tool execution failed: {run_result['error']}\n"
            f"Details: {run_result['message']}\n"
            f"Please try a different approach or use a different tool."
        )
    return {
        "type": "tool_result",
        "tool_use_id": tool_use_id,
        "content": content,
    }

// RefusalMessage.tsx - graceful display of safety refusals
export function RefusalMessage({
  suggestions,
  onSelectSuggestion,
}: {
  suggestions: string[];
  onSelectSuggestion: (s: string) => void;
}) {
  return (
    <div className="rounded-xl bg-slate-800 border border-slate-700 p-4 my-2">
      <p className="text-slate-300 text-sm mb-3">
        I am not able to help with that request. Here are some things I can help with:
      </p>
      <div className="flex flex-wrap gap-2">
        {suggestions.map(s => (
          <button key={s} onClick={() => onSelectSuggestion(s)}
                  className="text-xs bg-slate-700 hover:bg-slate-600 border border-slate-600
                             text-slate-300 rounded-full px-3 py-1">
            {s}
          </button>
        ))}
      </div>
    </div>
  );
}

// Detect a refusal from the assistant message text
function isRefusal(text: string): boolean {
  const lower = text.toLowerCase();
  return (
    lower.includes("i cannot") ||
    lower.includes("i am not able") ||
    lower.includes("i won't") ||
    lower.includes("i can't assist") ||
    lower.includes("i'm not able to help with that")
  );
}

